const canvas = document.getElementById('gc');
const ctx = canvas.getContext('2d');
const VW = 580, VH = 580;
canvas.width = VW; canvas.height = VH;

let audioCtx = null;
function getAudio() { if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)(); return audioCtx; }
function playNoise(dur, vol, lpFreq) {
  const ac = getAudio(), t = ac.currentTime;
  const buf = ac.createBuffer(1, Math.floor(ac.sampleRate * dur), ac.sampleRate);
  const d = buf.getChannelData(0);
  for (let i = 0; i < d.length; i++) d[i] = (Math.random()*2-1) * Math.pow(1 - i/d.length, 1.5);
  const src = ac.createBufferSource(), g = ac.createGain(), lp = ac.createBiquadFilter();
  lp.type = 'lowpass'; lp.frequency.value = lpFreq;
  g.gain.setValueAtTime(vol, t);
  src.buffer = buf; src.connect(lp); lp.connect(g); g.connect(ac.destination); src.start(t);
}
function playTone(freq, type, dur, vol, delay) {
  const ac = getAudio(), t = ac.currentTime + (delay || 0);
  const o = ac.createOscillator(), g = ac.createGain();
  o.connect(g); g.connect(ac.destination);
  o.type = type; o.frequency.setValueAtTime(freq, t);
  g.gain.setValueAtTime(vol || 0.2, t); g.gain.exponentialRampToValueAtTime(0.001, t + dur);
  o.start(t); o.stop(t + dur + 0.02);
}
function sfxShoot()    { playNoise(0.1, 0.28, 800); playTone(160,'square',0.06,0.05); }
function sfxShotgun()  { playNoise(0.16, 0.46, 520); playTone(95,'sawtooth',0.08,0.12); playTone(70,'sine',0.14,0.08,0.04); }
function sfxHit()      { playTone(200,'sawtooth',0.08,0.18); playTone(130,'sine',0.07,0.12,0.04); }
function sfxDeath()    { playTone(280,'sawtooth',0.05,0.22); playTone(100,'sine',0.18,0.2,0.08); }
function sfxHurt()     { playTone(90,'sawtooth',0.15,0.28); }
function sfxReload()   { playTone(480,'square',0.05,0.12); playTone(700,'square',0.05,0.08,0.07); }
function sfxBossRoar() { for (let i = 0; i < 6; i++) playTone(60 + i*15, 'sawtooth', 0.35, 0.18, i*0.06); }
function sfxWin()      { [523,659,784,1047,1319].forEach(function(n,i) { playTone(n,'sine',0.5,0.28,i*0.18); }); }

let musicOn = false, musicTimer = null;
function startMusic() {
  if (musicOn) return; musicOn = true;
  const bass = [55,58,55,52,55,58,62,50]; let bi = 0;
  musicTimer = setInterval(function() {
    if (!musicOn) return;
    const b = bass[bi % bass.length]; bi++;
    playTone(b, 'sawtooth', 0.2, 0.07);
    playTone(b * 2, 'square', 0.1, 0.03);
    if (bi % 4 === 0) playTone(220, 'sawtooth', 0.05, 0.04);
    if (bi % 8 === 3) { playTone(440,'square',0.03,0.03); playTone(550,'square',0.03,0.03,0.05); }
  }, 250);
}
function stopMusic() { musicOn = false; if (musicTimer) clearInterval(musicTimer); }

const mapImg = new Image(), colImg = new Image();
let mapW = 1110, mapH = 1417, colData;

function buildCollisionData() {
  const cc = document.createElement('canvas');
  cc.width = colImg.width; cc.height = colImg.height;
  const c2 = cc.getContext('2d'); c2.drawImage(colImg, 0, 0);
  colData = c2.getImageData(0, 0, colImg.width, colImg.height).data;
  mapW = colImg.width; mapH = colImg.height;
}
function solid(mx, my) {
  const x = Math.round(mx), y = Math.round(my);
  if (x < 0 || y < 0 || x >= mapW || y >= mapH) return true;
  const i = (y * mapW + x) * 4;
  return colData[i] > 140 && colData[i+1] < 80 && colData[i+2] < 80 && colData[i+3] > 40;
}
function collides(mx, my, hw, hh) {
  hw = hw || 7; hh = hh || 5;
  const pts = [[mx-hw,my-hh],[mx+hw,my-hh],[mx-hw,my+hh],[mx+hw,my+hh],[mx,my],[mx-hw,my],[mx+hw,my],[mx,my-hh],[mx,my+hh]];
  for (let i = 0; i < pts.length; i++) { if (solid(pts[i][0], pts[i][1])) return true; }
  return false;
}

const SCALE = VW / 185, PLAYER_SPD = 1.5, RELOAD_TIME = 120, WEAPON_RESPAWN_TIME = 1200;
const WEAPON_ORDER = ['pistol', 'shotgun', 'knife'];
const WEAPONS = {
  pistol:  { name:'HANDGUN', maxAmmo:12, pellets:1, damage:26, spread:0.035, bulletSpeed:5.2, bulletLife:82, fireRate:12, knockback:2.8, bulletSize:3.2, slot:1 },
  shotgun: { name:'SHOTGUN', maxAmmo:6,  pellets:7, damage:18, spread:0.34,  bulletSpeed:4.8, bulletLife:38, fireRate:30, knockback:5.4, bulletSize:2.6, slot:2 },
  knife:   { name:'KNIFE', maxAmmo:0, melee:true, damage:42, range:25, arc:0.9, fireRate:20, knockback:3.8, slot:3 }
};

// All state vars declared ONCE here
let gameState = 'menu';
let player, bullets, zombies, particles, pickups, corpses;
let camX, camY;
let mouseX, mouseY, mouseMapX, mouseMapY, mouseDown;
let killCount, bossSpawned, reloadCooldown, frameCount, lastShotFrame, weaponSpawnTick, meleeSlash;
let keys;

function initGame() {
  const s = findSpawn();
  player = {
    x:s.x, y:s.y, facing:'down', walkFrame:0, walkT:0, moving:false,
    hp:100, maxHp:100, weapon:'pistol',
    inventory:{ pistol:true, shotgun:false, knife:false },
    ammo:{ pistol:WEAPONS.pistol.maxAmmo, shotgun:0 },
    invincible:0
  };
  bullets = []; zombies = []; particles = []; pickups = []; corpses = [];
  camX = s.x; camY = s.y;
  mouseX = VW/2; mouseY = VH/2; mouseMapX = s.x; mouseMapY = s.y; mouseDown = false;
  keys = {};
  killCount = 0; bossSpawned = false; reloadCooldown = 0; frameCount = 0; lastShotFrame = -999; weaponSpawnTick = 0; meleeSlash = null;
  document.getElementById('bossBar').classList.remove('visible');
  refreshWeaponSpawns(true);
  showAnnounce('WAVE 1 - ZOMBIES NADEREN...');
  spawnWave(5);
  startMusic();
  updateHUD();
}

function findSpawn() {
  const cx = Math.floor(mapW * 0.35), cy = Math.floor(mapH * 0.55);
  for (let r = 1; r < 300; r++) {
    for (let a = 0; a < Math.PI * 2; a += 0.18) {
      const tx = Math.round(cx + Math.cos(a) * r), ty = Math.round(cy + Math.sin(a) * r);
      if (!collides(tx, ty)) return { x:tx, y:ty };
    }
  }
  return { x:cx, y:cy };
}

function dirForFacing(facing) {
  if (facing === 'up') return { x:0, y:-1 };
  if (facing === 'left') return { x:-1, y:0 };
  if (facing === 'right') return { x:1, y:0 };
  return { x:0, y:1 };
}

function lineClear(x1, y1, x2, y2) {
  const dist = Math.hypot(x2-x1, y2-y1), steps = Math.max(2, Math.ceil(dist / 6));
  for (let i = 1; i < steps; i++) {
    const t = i / steps;
    if (solid(x1 + (x2-x1)*t, y1 + (y2-y1)*t)) return false;
  }
  return true;
}

function findPickupSpot(x, y, dx, dy) {
  const px = -dy, py = dx;
  for (let d = 30; d <= 75; d += 5) {
    for (let s = 0; s <= 18; s += 6) {
      const tries = s ? [-s, s] : [0];
      for (let i = 0; i < tries.length; i++) {
        const tx = x + dx * d + px * tries[i], ty = y + dy * d + py * tries[i];
        if (!collides(tx, ty, 10, 7)) return { x:tx, y:ty };
      }
    }
  }
  return { x:x + dx * 34, y:y + dy * 34 };
}

function findReachableWeaponSpot(minDist, maxDist) {
  minDist = minDist || 80; maxDist = maxDist || 235;
  for (let i = 0; i < 130; i++) {
    const a = Math.random() * Math.PI * 2;
    const d = minDist + Math.random() * (maxDist - minDist);
    const x = player.x + Math.cos(a) * d, y = player.y + Math.sin(a) * d;
    if (!collides(x, y, 12, 8) && lineClear(player.x, player.y, x, y)) return { x:x, y:y };
  }
  const facing = dirForFacing(player.facing);
  return findPickupSpot(player.x, player.y, facing.x, facing.y);
}

function spawnWeaponPickup(type, spot) {
  pickups.push({ type:type, x:spot.x, y:spot.y, bob:Math.random()*Math.PI*2, pulse:0 });
}

function refreshWeaponSpawns(firstSpawn) {
  pickups = [];
  if (firstSpawn) {
    const d = dirForFacing(player.facing);
    spawnWeaponPickup('shotgun', findPickupSpot(player.x, player.y, d.x, d.y));
    spawnWeaponPickup('knife', findReachableWeaponSpot(65, 150));
    spawnWeaponPickup('pistol', findReachableWeaponSpot(100, 210));
  } else {
    const pool = ['shotgun', 'pistol', 'knife'];
    for (let i = 0; i < 3; i++) spawnWeaponPickup(pool[i], findReachableWeaponSpot(75, 245));
    showAnnounce('NIEUWE WAPENS OP DE MAP');
  }
  weaponSpawnTick = 0;
}

function weaponAmmo(type) {
  if (WEAPONS[type].melee) return 0;
  return player.ammo[type] || 0;
}

function setWeaponAmmo(type, value) {
  if (WEAPONS[type].melee) return;
  player.ammo[type] = Math.max(0, Math.min(WEAPONS[type].maxAmmo, value));
}

function switchWeapon(type) {
  if (!WEAPONS[type] || !player.inventory[type]) return;
  player.weapon = type;
  reloadCooldown = 0;
  lastShotFrame = -999;
  updateHUD();
}

function collectPickups() {
  for (let i = pickups.length - 1; i >= 0; i--) {
    const p = pickups[i];
    if (Math.hypot(player.x-p.x, player.y-p.y) < 14) {
      player.inventory[p.type] = true;
      if (!WEAPONS[p.type].melee) setWeaponAmmo(p.type, WEAPONS[p.type].maxAmmo);
      player.weapon = p.type;
      reloadCooldown = 0;
      pickups.splice(i, 1);
      spawnParticles(p.x, p.y, '#ffcc44', 14, 1.8, 22, 38, 1.5, 3.2);
      sfxReload();
      showAnnounce(WEAPONS[p.type].name + ' OPGEPAKT');
      updateHUD();
    }
  }
}

const ZTYPES = [
  { hp:30, spd:0.38, dmg:10, col:'#6f7f58', shirt:'#4b3f36', pants:'#262826', hair:'#2b241d', skin:'#9d987f', size:1.08 },
  { hp:15, spd:0.70, dmg:7,  col:'#7f735d', shirt:'#5c4637', pants:'#30302a', hair:'#3c3027', skin:'#b0a38b', size:0.95 },
  { hp:70, spd:0.22, dmg:20, col:'#5f684c', shirt:'#3c4a34', pants:'#211f1d', hair:'#1f1b18', skin:'#8e8874', size:1.42 }
];

function spawnWave(count) {
  for (let i = 0; i < count; i++) {
    (function(delay) {
      setTimeout(function() { if (gameState === 'playing') spawnZombie(false); }, delay);
    })(i * 900 + Math.random() * 300);
  }
}

function spawnZombie(isBoss) {
  const angle = Math.random() * Math.PI * 2, dist = 130 + Math.random() * 60;
  let x = player.x + Math.cos(angle) * dist, y = player.y + Math.sin(angle) * dist;
  for (let r = 0; r < 60; r++) { if (!collides(x, y)) break; x += Math.cos(angle + Math.PI)*2; y += Math.sin(angle + Math.PI)*2; }
  if (isBoss) {
    zombies.push({ x:x, y:y, hp:500, maxHp:500, spd:0.22, dmg:25, col:'#cc0000', shirt:'#2a0000', pants:'#130000', hair:'#111', skin:'#7a5533', size:2.2, isBoss:true, walkFrame:0, walkT:0, attackCooldown:0, stuckTime:0, lastX:x, lastY:y, sway:Math.random()*Math.PI*2 });
    document.getElementById('bossBar').classList.add('visible');
    document.getElementById('bossBarFill').style.width = '100%';
    sfxBossRoar(); showAnnounce('DON BOSCO IS ONTWAAKT');
  } else {
    const t = ZTYPES[Math.floor(Math.random() * ZTYPES.length)];
    zombies.push({ x:x, y:y, hp:t.hp, maxHp:t.hp, spd:t.spd*(0.85+Math.random()*0.3), dmg:t.dmg, col:t.col, shirt:t.shirt, pants:t.pants, hair:t.hair, skin:t.skin, size:t.size, isBoss:false, walkFrame:0, walkT:0, attackCooldown:0, stuckTime:0, lastX:x, lastY:y, sway:Math.random()*Math.PI*2 });
  }
}

function shoot() {
  if (reloadCooldown > 0) return;
  const w = WEAPONS[player.weapon];
  if (frameCount - lastShotFrame < w.fireRate) return;
  if (w.melee) { meleeAttack(w); return; }
  if (weaponAmmo(player.weapon) <= 0) { startReload(); return; }
  const dx = mouseMapX - player.x, dy = mouseMapY - player.y, base = Math.atan2(dy, dx);
  const muzzleX = player.x + Math.cos(base) * 8, muzzleY = player.y + Math.sin(base) * 8;
  for (let i = 0; i < w.pellets; i++) {
    const spread = (Math.random() - 0.5) * w.spread;
    const a = base + spread;
    const spd = w.bulletSpeed * (0.92 + Math.random() * 0.16);
    bullets.push({
      x:muzzleX, y:muzzleY, px:muzzleX, py:muzzleY,
      vx:Math.cos(a)*spd, vy:Math.sin(a)*spd,
      life:w.bulletLife + Math.random()*8,
      damage:w.damage, knockback:w.knockback, size:w.bulletSize,
      weapon:player.weapon
    });
  }
  setWeaponAmmo(player.weapon, weaponAmmo(player.weapon) - 1); lastShotFrame = frameCount;
  if (player.weapon === 'shotgun') sfxShotgun(); else sfxShoot();
  if (weaponAmmo(player.weapon) <= 0) startReload();
  updateHUD();
}

function meleeAttack(w) {
  const dx = mouseMapX - player.x, dy = mouseMapY - player.y, base = Math.atan2(dy, dx);
  let hitAny = false;
  meleeSlash = { x:player.x, y:player.y, angle:base, life:10, maxLife:10 };
  for (let j = zombies.length - 1; j >= 0; j--) {
    const z = zombies[j], zx = z.x - player.x, zy = z.y - player.y;
    const dist = Math.hypot(zx, zy);
    let diff = Math.atan2(Math.sin(Math.atan2(zy, zx)-base), Math.cos(Math.atan2(zy, zx)-base));
    if (dist < w.range + (z.isBoss ? 10 : 5*z.size) && Math.abs(diff) < w.arc) {
      z.hp -= w.damage;
      knockZombie(z, { vx:Math.cos(base), vy:Math.sin(base), knockback:w.knockback });
      spawnBloodImpact(z.x, z.y, { vx:Math.cos(base)*3, vy:Math.sin(base)*3 }, z);
      if (z.hp <= 0) killZombie(j, z.isBoss);
      else if (z.isBoss) document.getElementById('bossBarFill').style.width = (z.hp/z.maxHp*100)+'%';
      hitAny = true;
    }
  }
  lastShotFrame = frameCount;
  if (hitAny) sfxHit(); else playTone(420, 'square', 0.05, 0.08);
  updateHUD();
}

function startReload() {
  if (reloadCooldown > 0) return;
  if (WEAPONS[player.weapon].melee) return;
  if (weaponAmmo(player.weapon) >= WEAPONS[player.weapon].maxAmmo) return;
  reloadCooldown = RELOAD_TIME; sfxReload(); updateHUD();
}

function spawnParticles(x, y, col, n, spd, minLife, maxLife, minSize, maxSize) {
  n = n||6; spd = spd||1.5;
  for (let i = 0; i < n; i++) {
    const a = Math.random() * Math.PI * 2;
    const life = (minLife || 18) + Math.random() * ((maxLife || 32) - (minLife || 18));
    particles.push({ x:x, y:y, vx:Math.cos(a)*spd*(0.4+Math.random()), vy:Math.sin(a)*spd*(0.4+Math.random()), life:life, maxLife:life, col:col, size:(minSize || 1.5)+Math.random()*((maxSize || 3.5)-(minSize || 1.5)) });
  }
}

function distPointToSegment(px, py, x1, y1, x2, y2) {
  const dx = x2 - x1, dy = y2 - y1, len2 = dx*dx + dy*dy;
  if (!len2) return Math.hypot(px-x1, py-y1);
  const t = Math.max(0, Math.min(1, ((px-x1)*dx + (py-y1)*dy) / len2));
  return Math.hypot(px - (x1 + dx*t), py - (y1 + dy*t));
}

function spawnDirectionalParticles(x, y, vx, vy, colors, n, spd, spread, minLife, maxLife, minSize, maxSize) {
  const base = Math.atan2(vy, vx);
  for (let i = 0; i < n; i++) {
    const a = base + (Math.random() - 0.5) * spread;
    const life = minLife + Math.random() * (maxLife - minLife);
    particles.push({
      x:x, y:y,
      vx:Math.cos(a)*spd*(0.45+Math.random()),
      vy:Math.sin(a)*spd*(0.45+Math.random()),
      life:life, maxLife:life,
      col:colors[Math.floor(Math.random()*colors.length)],
      size:minSize + Math.random() * (maxSize - minSize)
    });
  }
}

function spawnBloodImpact(x, y, b, z) {
  const blood = z.isBoss ? ['#aa0000','#dd1616','#4d0000'] : ['#8b0000','#bb1111','#4b0000'];
  spawnDirectionalParticles(x, y, b.vx, b.vy, blood, z.isBoss ? 12 : 7, z.isBoss ? 2.8 : 2.1, 1.35, 24, 52, 1.2, 3.4);
  spawnParticles(x, y, blood[0], z.isBoss ? 8 : 4, 1.2, 22, 44, 1.6, 4.2);
}

function spawnWallImpact(b) {
  spawnDirectionalParticles(b.x, b.y, -b.vx, -b.vy, ['#ffd866','#ff9f1a','#ddd'], 5, 1.7, 1.0, 10, 22, 1, 2.2);
}

function knockZombie(z, b) {
  const len = Math.hypot(b.vx, b.vy) || 1;
  const force = b.knockback * (z.isBoss ? 0.35 : 1);
  const kx = b.vx / len * force, ky = b.vy / len * force;
  const hw = z.isBoss ? 8 : 4, hh = z.isBoss ? 6 : 3;
  if (!collides(z.x + kx, z.y + ky, hw, hh)) { z.x += kx; z.y += ky; return; }
  if (!collides(z.x + kx, z.y, hw, hh)) z.x += kx;
  if (!collides(z.x, z.y + ky, hw, hh)) z.y += ky;
}

function leaveCorpse(z, isBoss) {
  const life = isBoss ? 620 : 360;
  corpses.push({ x:z.x, y:z.y, size:z.size, col:z.col, shirt:z.shirt, skin:z.skin, isBoss:isBoss, rot:(Math.random()-0.5)*1.2, life:life, maxLife:life });
}

function updateHUD() {
  document.getElementById('hudHp').textContent    = 'HP ' + player.hp;
  document.getElementById('hudWeapon').textContent = WEAPONS[player.weapon].name;
  document.getElementById('hudAmmo').textContent  = WEAPONS[player.weapon].melee ? 'MELEE' : (reloadCooldown > 0 ? 'RELOADING' : weaponAmmo(player.weapon) + '/' + WEAPONS[player.weapon].maxAmmo);
  document.getElementById('hudKills').textContent = killCount + ' KILLS';
  document.getElementById('hudWave').textContent  = bossSpawned ? 'BOSS!' : killCount + '/15';
  updateWeaponBar();
}

function updateWeaponBar() {
  for (let i = 0; i < WEAPON_ORDER.length; i++) {
    const type = WEAPON_ORDER[i], w = WEAPONS[type];
    const slot = document.querySelector('.weapon-slot[data-weapon="'+type+'"]');
    if (!slot) continue;
    slot.classList.toggle('active', player.weapon === type);
    slot.classList.toggle('locked', !player.inventory[type]);
    const ammoEl = slot.querySelector('.weapon-ammo');
    if (!player.inventory[type]) ammoEl.textContent = 'LOCKED';
    else ammoEl.textContent = w.melee ? 'MELEE' : weaponAmmo(type) + '/' + w.maxAmmo;
  }
}

function showAnnounce(txt) {
  const el = document.getElementById('waveAnnounce');
  el.textContent = txt; el.classList.add('show');
  setTimeout(function() { el.classList.remove('show'); }, 2800);
}

function mapToScreen(mx, my) { return [(mx-camX)*SCALE+VW/2, (my-camY)*SCALE+VH/2]; }
function screenToMap(sx, sy)  { return [(sx-VW/2)/SCALE+camX, (sy-VH/2)/SCALE+camY]; }

function drawPlayer() {
  if (player.invincible > 0 && Math.floor(player.invincible/3) % 2 === 0) return;
  const P = 2.25, ls = player.walkFrame % 2 === 0 ? 1 : -1;
  const bob = player.moving ? Math.sin(frameCount * 0.28) * 0.7 : 0;
  ctx.save(); ctx.translate(VW/2, VH/2 + bob);
  if (player.facing === 'left') ctx.scale(-1, 1);
  function px(x,y,w,h,c) { ctx.fillStyle=c; ctx.fillRect(x*P,y*P,w*P,h*P); }
  ctx.fillStyle='rgba(0,0,0,0.35)'; ctx.beginPath(); ctx.ellipse(0,10*P,5*P,1.15*P,0,0,Math.PI*2); ctx.fill();
  px(-2.4,5.2+ls*0.7,2,3.5,'#101014'); px(0.4,5.2-ls*0.7,2,3.5,'#101014');
  px(-2.4,8.5+ls*0.7,2.2,1,'#090909'); px(0.3,8.5-ls*0.7,2.2,1,'#090909');
  px(-3.4,0.2,6.8,6.8,'#060607');
  px(-2.3,1.1,1,5.6,'#202126'); px(1.3,1.1,1,5.6,'#202126');
  px(-1.2,0.6,2.4,5.9,'#111217');
  px(-4.7,1.1-ls*0.55,1.4,4.2,'#09090b'); px(3.3,1.1+ls*0.55,1.4,4.2,'#09090b');
  px(-4.6,4.7-ls*0.55,1.2,1.1,'#d7a66a'); px(3.5,4.7+ls*0.55,1.2,1.1,'#d7a66a');
  if (player.weapon === 'shotgun') {
    ctx.fillStyle='#6b3f1d'; ctx.fillRect(2.3*P,2.4*P,4.2*P,1.5*P);
    ctx.fillStyle='#999'; ctx.fillRect(5.5*P,2.2*P,6.6*P,0.65*P); ctx.fillRect(5.5*P,3.1*P,6.6*P,0.65*P);
  } else if (player.weapon === 'knife') {
    ctx.fillStyle='#dbe7ee'; ctx.fillRect(4.1*P,2.1*P,1.1*P,5.4*P);
    ctx.fillStyle='#333'; ctx.fillRect(3.8*P,6.8*P,1.8*P,1.1*P);
  } else {
    ctx.fillStyle='#222'; ctx.fillRect(2.7*P,2.4*P,4.2*P,1.5*P);
    ctx.fillStyle='#999'; ctx.fillRect(5.9*P,2.3*P,2.4*P,0.8*P);
  }
  px(-2.2,-3.7,4.4,4.5,'#d7a66a'); px(-2.3,-3.9,4.6,1.1,'#1c1510');
  if (player.facing !== 'up') {
    px(-2.2,-2.1,1.7,0.9,'#060606'); px(0.5,-2.1,1.7,0.9,'#060606');
    px(-0.5,-1.95,1,0.25,'#111');
  }
  ctx.restore();
}

function drawZombie(z) {
  const sc = mapToScreen(z.x, z.y), sx = sc[0], sy = sc[1];
  if (sx < -100 || sx > VW+100 || sy < -100 || sy > VH+100) return;
  const P = 2 * z.size, ls = z.walkFrame % 2 === 0 ? 1 : -1;
  ctx.save(); ctx.translate(sx, sy);
  if (z.isBoss) {
    const B = P * 0.6;
    ctx.fillStyle='rgba(0,0,0,0.45)'; ctx.beginPath(); ctx.ellipse(0,14*B,8*B,2*B,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle='#2a0000'; ctx.fillRect(-6*B,-3*B,12*B,16*B);
    ctx.fillStyle='#1a0000'; ctx.fillRect(-10*B,0,4*B,2*B); ctx.fillRect(6*B,0,4*B,2*B);
    ctx.fillStyle='#888';
    for (let i=0;i<3;i++) { ctx.fillRect(-10*B-B*0.5,2*B+i*B*0.8,B,B*0.5); ctx.fillRect(10*B-B*0.5,2*B+i*B*0.8,B,B*0.5); }
    ctx.fillStyle='#7a5533'; ctx.fillRect(-5*B,-10*B,10*B,8*B);
    ctx.fillStyle='#ff0000'; ctx.fillRect(-4*B,-8*B,3*B,2*B); ctx.fillRect(1*B,-8*B,3*B,2*B);
    ctx.fillStyle='#ffaa00'; ctx.fillRect(-3*B,-7.5*B,1.5*B,1*B); ctx.fillRect(2*B,-7.5*B,1.5*B,1*B);
    ctx.fillStyle='#111'; ctx.fillRect(-5*B,-11*B,10*B,2*B); ctx.fillRect(-3.5*B,-15*B,7*B,4.5*B);
    ctx.fillStyle='rgba(0,0,0,0.75)'; ctx.fillRect(-30,-22,60,14);
    ctx.fillStyle='#ff2222'; ctx.font='11px VT323,monospace'; ctx.textAlign='center'; ctx.textBaseline='middle';
    ctx.fillText('DON BOSCO', 0, -15);
  } else {
    function bx(x,y,w,h,c) { ctx.fillStyle=c; ctx.fillRect(x*P,y*P,w*P,h*P); }
    const wobble = Math.sin(frameCount*0.08 + z.sway) * 0.09;
    ctx.fillStyle='rgba(0,0,0,0.28)'; ctx.beginPath(); ctx.ellipse(0,9.5*P,4.2*P,1.0*P,0,0,Math.PI*2); ctx.fill();
    ctx.save(); ctx.rotate(wobble);
    bx(-2.3,5+ls,2.1,3.3,z.pants || '#252525'); bx(0.3,5-ls,2.1,3.3,z.pants || '#252525');
    bx(-2.5,8+ls,2.3,0.9,'#171717'); bx(0.2,8-ls,2.3,0.9,'#171717');
    bx(-3.0,0.6,6,4.9,z.shirt || '#4b3f36');
    bx(-3.0,3.7,1.6,1.1,'#281711'); bx(1.2,1.4,1.7,1.1,'#2c2a24');
    bx(-5.5,0.1+ls*0.35,2.4,1.5,z.shirt || '#4b3f36'); bx(3.1,0.8-ls*0.45,2.7,1.4,z.shirt || '#4b3f36');
    bx(-6.2,1.2+ls*0.35,1.4,1.4,z.skin || '#9d987f'); bx(4.9,1.8-ls*0.45,1.4,1.4,z.skin || '#9d987f');
    bx(-2.2,-3.3,4.4,4.3,z.skin || '#9d987f');
    bx(-2.4,-3.5,4.8,1.2,z.hair || '#2b241d');
    bx(-1.5,-2.0,1,0.9,'#e7d34b'); bx(0.5,-2.0,1,0.9,'#e7d34b');
    bx(-1.4,-0.6,2.8,0.65,'#1a0908');
    bx(1.7,-2.7,1.1,1.2,'#6d1b16');
    bx(-2.8,1.7,1,1.5,'#6d1b16');
    ctx.restore();
    const hp = z.hp/z.maxHp;
    ctx.fillStyle='rgba(0,0,0,0.6)'; ctx.fillRect(-12,-15,24,4);
    ctx.fillStyle = hp>0.5?'#44ff44':hp>0.25?'#ffaa00':'#ff2222';
    ctx.fillRect(-12,-15,24*hp,4);
  }
  ctx.restore();
}

function drawBullet(b) {
  const sc = mapToScreen(b.x, b.y);
  const tail = mapToScreen(b.x - b.vx*1.7, b.y - b.vy*1.7);
  ctx.save();
  ctx.strokeStyle = b.weapon === 'shotgun' ? '#ffdf8a' : '#fff1a8';
  ctx.lineWidth = b.size;
  ctx.lineCap = 'round';
  ctx.shadowColor = '#ffb000';
  ctx.shadowBlur = 8;
  ctx.beginPath(); ctx.moveTo(tail[0], tail[1]); ctx.lineTo(sc[0], sc[1]); ctx.stroke();
  ctx.fillStyle = '#fff8cf';
  ctx.beginPath(); ctx.arc(sc[0], sc[1], Math.max(1.4, b.size*0.55), 0, Math.PI*2); ctx.fill();
  ctx.restore();
}

function drawMeleeSlash() {
  if (!meleeSlash) return;
  const alpha = meleeSlash.life / meleeSlash.maxLife;
  ctx.save();
  ctx.translate(VW/2, VH/2);
  ctx.rotate(meleeSlash.angle);
  ctx.globalAlpha = alpha;
  ctx.strokeStyle = '#dbe7ee';
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.arc(0, 0, 26, -0.55, 0.55);
  ctx.stroke();
  ctx.strokeStyle = 'rgba(255,255,255,0.55)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.arc(0, 0, 31, -0.42, 0.42);
  ctx.stroke();
  ctx.restore();
  ctx.globalAlpha = 1;
}

function drawPickup(p) {
  const sc = mapToScreen(p.x, p.y), sx = sc[0], sy = sc[1] + Math.sin(frameCount*0.08 + p.bob) * 2;
  if (sx < -50 || sx > VW+50 || sy < -50 || sy > VH+50) return;
  ctx.save(); ctx.translate(sx, sy);
  ctx.fillStyle='rgba(255,205,60,0.18)'; ctx.beginPath(); ctx.arc(0,0,18+Math.sin(frameCount*0.08)*2,0,Math.PI*2); ctx.fill();
  ctx.strokeStyle='rgba(255,230,120,0.55)'; ctx.lineWidth=1; ctx.beginPath(); ctx.arc(0,0,17,0,Math.PI*2); ctx.stroke();
  ctx.rotate(p.type === 'knife' ? 0.65 : -0.35);
  ctx.fillStyle='rgba(0,0,0,0.35)'; ctx.fillRect(-15,5,32,3);
  if (p.type === 'shotgun') {
    ctx.fillStyle='#6b3f1d'; ctx.fillRect(-15,-3,9,6); ctx.fillRect(-9,1,7,4);
    ctx.fillStyle='#bbb'; ctx.fillRect(-4,-4,24,2); ctx.fillRect(-4,0,24,2);
    ctx.fillStyle='#2b2b2b'; ctx.fillRect(1,-2,5,4);
  } else if (p.type === 'pistol') {
    ctx.fillStyle='#2b2b2b'; ctx.fillRect(-8,-4,14,6); ctx.fillRect(1,1,5,8);
    ctx.fillStyle='#aeb6bb'; ctx.fillRect(5,-3,11,3);
  } else {
    ctx.fillStyle='#d9e2e7'; ctx.fillRect(-2,-15,4,22);
    ctx.fillStyle='#f5f8fa'; ctx.fillRect(-1,-16,2,16);
    ctx.fillStyle='#3a2418'; ctx.fillRect(-3,6,6,11);
  }
  ctx.restore();
}

function drawCorpse(c) {
  const sc = mapToScreen(c.x, c.y), sx = sc[0], sy = sc[1];
  if (sx < -120 || sx > VW+120 || sy < -120 || sy > VH+120) return;
  const fade = Math.min(1, c.life / 70), P = 2 * c.size;
  ctx.save(); ctx.globalAlpha = fade; ctx.translate(sx, sy);
  ctx.fillStyle = c.isBoss ? 'rgba(100,0,0,0.45)' : 'rgba(115,0,0,0.38)';
  ctx.beginPath(); ctx.ellipse(0, 6*P, 9*P, 3.3*P, c.rot*0.35, 0, Math.PI*2); ctx.fill();
  ctx.rotate(c.rot);
  ctx.fillStyle='rgba(0,0,0,0.35)'; ctx.beginPath(); ctx.ellipse(0,8*P,5*P,1.2*P,0,0,Math.PI*2); ctx.fill();
  ctx.fillStyle = c.isBoss ? '#3b0000' : (c.shirt || c.col);
  ctx.fillRect(-5*P,-1*P,10*P,5*P);
  ctx.fillStyle = c.isBoss ? '#7a5533' : (c.skin || '#8f8874');
  ctx.fillRect(4*P,-2*P,4*P,4*P);
  ctx.fillStyle='#311'; ctx.fillRect(-7*P,1*P,3*P,1.5*P); ctx.fillRect(3*P,4*P,4*P,1.5*P);
  ctx.restore(); ctx.globalAlpha = 1;
}

function update() {
  frameCount++;
  let dx = 0, dy = 0;
  if (keys['ArrowLeft']  || keys['a'] || keys['A']) dx -= 1;
  if (keys['ArrowRight'] || keys['d'] || keys['D']) dx += 1;
  if (keys['ArrowUp']    || keys['w'] || keys['W']) dy -= 1;
  if (keys['ArrowDown']  || keys['s'] || keys['S']) dy += 1;
  if (dx && dy) { dx *= 0.707; dy *= 0.707; }
  player.moving = !!(dx || dy);
  if (player.moving) {
    const nx = player.x + dx * PLAYER_SPD; if (!collides(nx, player.y)) player.x = nx;
    const ny = player.y + dy * PLAYER_SPD; if (!collides(player.x, ny)) player.y = ny;
    player.walkT++;
    if (player.walkT > 7) { player.walkT = 0; player.walkFrame = (player.walkFrame+1)%4; }
  } else { player.walkFrame = 0; }
  collectPickups();
  if (player.invincible > 0) player.invincible--;
  if (reloadCooldown > 0) { reloadCooldown--; if (reloadCooldown <= 0) { setWeaponAmmo(player.weapon, WEAPONS[player.weapon].maxAmmo); updateHUD(); } }
  weaponSpawnTick++;
  if (weaponSpawnTick >= WEAPON_RESPAWN_TIME) refreshWeaponSpawns(false);
  if (meleeSlash) { meleeSlash.life--; if (meleeSlash.life <= 0) meleeSlash = null; }
  if (mouseDown && reloadCooldown <= 0) shoot();

  const mm = screenToMap(mouseX, mouseY); mouseMapX = mm[0]; mouseMapY = mm[1];
  const fdy = mouseMapY - player.y, fdx = mouseMapX - player.x;
  if (Math.abs(fdx) >= Math.abs(fdy)) player.facing = fdx > 0 ? 'right' : 'left';
  else player.facing = fdy > 0 ? 'down' : 'up';

  camX += (player.x - camX) * 0.1;
  camY += (player.y - camY) * 0.1;

  for (let i = bullets.length - 1; i >= 0; i--) {
    const b = bullets[i];
    b.px = b.x; b.py = b.y;
    b.x += b.vx; b.y += b.vy; b.life--;
    if (b.life <= 0 || solid(b.x, b.y)) { spawnWallImpact(b); bullets.splice(i,1); continue; }
    let hit = false;
    for (let j = zombies.length - 1; j >= 0; j--) {
      const z = zombies[j];
      if (distPointToSegment(z.x, z.y, b.px, b.py, b.x, b.y) < (z.isBoss?15:7*z.size)) {
        z.hp -= b.damage;
        knockZombie(z, b);
        spawnBloodImpact(b.x, b.y, b, z);
        sfxHit();
        if (z.hp <= 0) killZombie(j, z.isBoss);
        else if (z.isBoss) document.getElementById('bossBarFill').style.width = (z.hp/z.maxHp*100)+'%';
        hit = true; break;
      }
    }
    if (hit) bullets.splice(i, 1);
  }

  for (let i = 0; i < zombies.length; i++) {
    const z = zombies[i];
    // check of zombie vastzit
    const moveDist = Math.hypot(z.x - z.lastX, z.y - z.lastY);

    if (moveDist < 0.1) {
      z.stuckTime++;
    } else {
      z.stuckTime = 0;
    }

z.lastX = z.x;
z.lastY = z.y;

// als te lang vast: respawn
if (z.stuckTime > 120) { // ~2 seconden
  zombies.splice(i, 1);
  spawnZombie(z.isBoss);
  continue;
}
    const tx = player.x - z.x, ty = player.y - z.y, tlen = Math.hypot(tx,ty)||1;
    const nx = z.x + tx/tlen*z.spd, ny = z.y + ty/tlen*z.spd;
    if      (!collides(nx,ny,4,3))                   { z.x=nx; z.y=ny; }
    else if (!collides(z.x+tx/tlen*z.spd,z.y,4,3))  z.x += tx/tlen*z.spd;
    else if (!collides(z.x,z.y+ty/tlen*z.spd,4,3))  z.y += ty/tlen*z.spd;
    z.walkT = (z.walkT||0) + 1;
    if (z.walkT > 6) { z.walkT=0; z.walkFrame=(z.walkFrame+1)%4; }
    const dist = Math.hypot(player.x-z.x, player.y-z.y);
    z.attackCooldown = (z.attackCooldown||0) - 1;
    if (dist < (z.isBoss?16:8) && z.attackCooldown <= 0 && player.invincible <= 0) {
      player.hp = Math.max(0, player.hp - z.dmg);
      player.invincible = 45; z.attackCooldown = z.isBoss ? 40 : 55;
      sfxHurt(); spawnParticles(player.x,player.y,'#ff3333',8,2); updateHUD();
      if (player.hp <= 0) { endGame(false); return; }
    }
  }

  if (!bossSpawned) {
    if (killCount >= 15) {
      bossSpawned = true;

      // eerst alles clearen
      zombies = [];

      setTimeout(function() {
        if (gameState === 'playing') spawnZombie(true);
      }, 1500);

    } else if (zombies.length === 0) {
      spawnWave(3 + Math.floor(killCount / 3));
    }
}

  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i]; p.x+=p.vx; p.y+=p.vy; p.vx*=0.88; p.vy*=0.88; p.life--;
    if (p.life <= 0) particles.splice(i, 1);
  }
  for (let i = corpses.length - 1; i >= 0; i--) {
    corpses[i].life--;
    if (corpses[i].life <= 0) corpses.splice(i, 1);
  }
}

function killZombie(idx, isBoss) {
  const z = zombies[idx];
  leaveCorpse(z, isBoss);
  spawnParticles(z.x, z.y, '#770000', isBoss?28:14, isBoss?3.6:2.4, 28, 64, 1.8, 5);
  sfxDeath(); zombies.splice(idx, 1);
  if (isBoss) { endGame(true); return; }
  killCount++; updateHUD();
}

function render() {
  ctx.clearRect(0,0,VW,VH); ctx.fillStyle='#060606'; ctx.fillRect(0,0,VW,VH);
  ctx.save(); ctx.imageSmoothingEnabled=false;
  ctx.drawImage(mapImg, VW/2-camX*SCALE, VH/2-camY*SCALE, mapW*SCALE, mapH*SCALE);
  ctx.restore();
  for (let i=0;i<corpses.length;i++) drawCorpse(corpses[i]);
  for (let i=0;i<pickups.length;i++) drawPickup(pickups[i]);
  for (let i=0;i<particles.length;i++) {
    const p=particles[i], sc=mapToScreen(p.x,p.y);
    ctx.globalAlpha=p.life/p.maxLife; ctx.fillStyle=p.col;
    ctx.fillRect(sc[0]-p.size/2, sc[1]-p.size/2, p.size, p.size);
  }
  ctx.globalAlpha=1;
  for (let i=0;i<bullets.length;i++) drawBullet(bullets[i]);
  drawMeleeSlash();
  for (let i=0;i<zombies.length;i++) drawZombie(zombies[i]);
  drawPlayer();
  ctx.save(); ctx.strokeStyle='rgba(255,255,80,0.8)'; ctx.lineWidth=1;
  ctx.beginPath(); ctx.moveTo(mouseX-9,mouseY); ctx.lineTo(mouseX+9,mouseY); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(mouseX,mouseY-9); ctx.lineTo(mouseX,mouseY+9); ctx.stroke();
  ctx.beginPath(); ctx.arc(mouseX,mouseY,5,0,Math.PI*2); ctx.stroke(); ctx.restore();
  const vig=ctx.createRadialGradient(VW/2,VH/2,VW*0.1,VW/2,VH/2,VW*0.78);
  vig.addColorStop(0,'rgba(0,0,0,0)'); vig.addColorStop(1,'rgba(0,0,0,0.65)');
  ctx.fillStyle=vig; ctx.fillRect(0,0,VW,VH);
  const hpPct=player.hp/player.maxHp;
  ctx.fillStyle='rgba(0,0,0,0.6)'; ctx.fillRect(10,VH-22,100,8);
  ctx.fillStyle=hpPct>0.5?'#44ff44':hpPct>0.25?'#ffaa00':'#ff2222'; ctx.fillRect(10,VH-22,100*hpPct,8);
  ctx.fillStyle='#ddd'; ctx.font='13px VT323,monospace'; ctx.textAlign='left'; ctx.fillText('HP '+player.hp,10,VH-26);
  if (reloadCooldown>0) {
    const pct=1-reloadCooldown/RELOAD_TIME;
    ctx.fillStyle='rgba(0,0,0,0.65)'; ctx.fillRect(VW/2-55,VH-30,110,10);
    ctx.fillStyle='#ffcc00'; ctx.fillRect(VW/2-55,VH-30,110*pct,10);
    ctx.fillStyle='#ffcc00'; ctx.font='13px VT323,monospace'; ctx.textAlign='center'; ctx.fillText('RELOADING',VW/2,VH-33);
  }
}

function endGame(won) {
  gameState = won ? 'win' : 'dead'; stopMusic();
  document.getElementById('endTitle').textContent = won ? 'GEWONNEN!' : 'GAME OVER';
  document.getElementById('endTitle').className   = won ? 'green-title' : 'red-title';
  document.getElementById('endMsg').textContent   = won ? 'Don Bosco is verslagen! '+killCount+' zombies ge-elimineerd.' : 'Gevallen na '+killCount+' kills. Probeer opnieuw!';
  document.getElementById('endScreen').classList.add('active');
  document.getElementById('hud').classList.remove('visible');
  document.getElementById('weaponBar').classList.remove('visible');
  document.getElementById('bossBar').classList.remove('visible');
  if (won) sfxWin();
}

window.addEventListener('keydown', function(e) {
  if (keys) keys[e.key] = true;
  if (['ArrowUp','ArrowDown','ArrowLeft','ArrowRight',' '].includes(e.key)) e.preventDefault();
  if (gameState==='playing' && e.key >= '1' && e.key <= '3') switchWeapon(WEAPON_ORDER[Number(e.key)-1]);
  if ((e.key==='r'||e.key==='R') && gameState==='playing') startReload();
});
window.addEventListener('keyup', function(e) { if (keys) keys[e.key] = false; });
canvas.addEventListener('mousemove', function(e) { const r=canvas.getBoundingClientRect(); mouseX=e.clientX-r.left; mouseY=e.clientY-r.top; });
canvas.addEventListener('mousedown', function(e) { if (e.button===0 && gameState==='playing') { mouseDown=true; shoot(); } });
canvas.addEventListener('mouseup', function(e) { if (e.button===0) mouseDown=false; });
canvas.addEventListener('contextmenu', function(e) { e.preventDefault(); });
canvas.style.cursor = 'none';

function gameLoop() { if (gameState!=='playing') return; update(); render(); requestAnimationFrame(gameLoop); }

document.getElementById('startBtn').addEventListener('click', function() {
  getAudio();
  document.getElementById('menuScreen').classList.remove('active');
  document.getElementById('hud').classList.add('visible');
  document.getElementById('weaponBar').classList.add('visible');
  gameState='playing'; initGame(); requestAnimationFrame(gameLoop);
});
document.getElementById('howBtn').addEventListener('click', function() { document.getElementById('menuScreen').classList.remove('active'); document.getElementById('howScreen').classList.add('active'); });
document.getElementById('backBtn').addEventListener('click', function() { document.getElementById('howScreen').classList.remove('active'); document.getElementById('menuScreen').classList.add('active'); });
document.getElementById('restartBtn').addEventListener('click', function() {
  document.getElementById('endScreen').classList.remove('active');
  document.getElementById('hud').classList.add('visible');
  document.getElementById('weaponBar').classList.add('visible');
  gameState='playing'; initGame(); requestAnimationFrame(gameLoop);
});
document.getElementById('menuBtn2').addEventListener('click', function() {
  document.getElementById('endScreen').classList.remove('active');
  document.getElementById('menuScreen').classList.add('active');
  document.getElementById('weaponBar').classList.remove('visible');
  gameState='menu';
});

let assetsLoaded = 0;
function onAssetLoad() { assetsLoaded++; if (assetsLoaded===2) buildCollisionData(); }
mapImg.onload = onAssetLoad; colImg.onload = onAssetLoad;

mapImg.src = 'data:image/jpeg;base64,';
colImg.src = 'data:image/png;base64,';

